// ── Code snippet generators ──────────────────────────────────────────────
function genCurl(ep) {
  const isBody = ep.body && ['POST', 'PUT', 'PATCH'].includes(ep.method);
  let cmd = `curl -X ${ep.method} 'https://auraalpha.cc${ep.path}'`;
  cmd += ` \\\n  -H 'Authorization: Bearer YOUR_TOKEN'`;
  cmd += ` \\\n  -H 'Content-Type: application/json'`;
  if (isBody && ep.body.fields) {
    const bodyObj = {};
    ep.body.fields.forEach(f => {
      if (f.type === 'string') bodyObj[f.name] = f.name === 'email' ? 'trader@example.com' : 'example';
      else if (f.type === 'integer') bodyObj[f.name] = 90;
      else if (f.type === 'number') bodyObj[f.name] = 0.5;
      else bodyObj[f.name] = 'value';
    });
    cmd += ` \\\n  -d '${JSON.stringify(bodyObj)}'`;
  }
  return cmd;
}

function genPython(ep) {
  const isBody = ep.body && ['POST', 'PUT', 'PATCH'].includes(ep.method);
  let code = `import requests\n\n`;
  code += `url = "https://auraalpha.cc${ep.path}"\n`;
  code += `headers = {\n    "Authorization": "Bearer YOUR_TOKEN",\n    "Content-Type": "application/json"\n}\n`;
  if (isBody && ep.body.fields) {
    const bodyObj = {};
    ep.body.fields.forEach(f => {
      if (f.type === 'string') bodyObj[f.name] = f.name === 'email' ? 'trader@example.com' : 'example';
      else if (f.type === 'integer') bodyObj[f.name] = 90;
      else if (f.type === 'number') bodyObj[f.name] = 0.5;
      else bodyObj[f.name] = 'value';
    });
    code += `payload = ${JSON.stringify(bodyObj, null, 4)}\n\n`;
    code += `response = requests.${ep.method.toLowerCase()}(url, headers=headers, json=payload)\n`;
  } else {
    code += `\nresponse = requests.${ep.method.toLowerCase()}(url, headers=headers)\n`;
  }
  code += `print(response.json())`;
  return code;
}

function genJavaScript(ep) {
  const isBody = ep.body && ['POST', 'PUT', 'PATCH'].includes(ep.method);
  let code = `const response = await fetch('https://auraalpha.cc${ep.path}', {\n`;
  code += `  method: '${ep.method}',\n`;
  code += `  headers: {\n    'Authorization': 'Bearer YOUR_TOKEN',\n    'Content-Type': 'application/json'\n  }`;
  if (isBody && ep.body.fields) {
    const bodyObj = {};
    ep.body.fields.forEach(f => {
      if (f.type === 'string') bodyObj[f.name] = f.name === 'email' ? 'trader@example.com' : 'example';
      else if (f.type === 'integer') bodyObj[f.name] = 90;
      else if (f.type === 'number') bodyObj[f.name] = 0.5;
      else bodyObj[f.name] = 'value';
    });
    code += `,\n  body: JSON.stringify(${JSON.stringify(bodyObj, null, 4).split('\n').map((l, i) => i === 0 ? l : '  ' + l).join('\n')})`;
  }
  code += `\n});\n\nconst data = await response.json();\nconsole.log(data);`;
  return code;
}

