// ── Try-It Panel ─────────────────────────────────────────────────────────
function TryItPanel({ endpoint }) {
  const [paramValues, setParamValues] = useState({});
  const [bodyValues, setBodyValues] = useState({});
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState(null);

  const updateParam = (name, value) => setParamValues(p => ({ ...p, [name]: value }));
  const updateBody = (name, value) => setBodyValues(b => ({ ...b, [name]: value }));

  const handleSend = async () => {
    setLoading(true);
    setResult(null);

    // Build the path with param substitution
    let path = endpoint.path;
    (endpoint.params || []).forEach(p => {
      if (p.required && paramValues[p.name]) {
        path = path.replace(`{${p.name}}`, encodeURIComponent(paramValues[p.name]));
      }
    });

    // Build query string from optional params
    const queryParams = (endpoint.params || [])
      .filter(p => !p.required && paramValues[p.name])
      .map(p => `${p.name}=${encodeURIComponent(paramValues[p.name])}`)
      .join('&');
    if (queryParams) path += `?${queryParams}`;

    // Strip the /api prefix since our api() helper adds it
    const apiPath = path.replace(/^\/api/, '');

    const start = performance.now();
    try {
      let data;
      if (['POST', 'PUT', 'PATCH'].includes(endpoint.method)) {
        const bodyPayload = {};
        (endpoint.body?.fields || []).forEach(f => {
          if (bodyValues[f.name] !== undefined && bodyValues[f.name] !== '') {
            bodyPayload[f.name] = f.type === 'integer' ? parseInt(bodyValues[f.name], 10)
              : f.type === 'number' ? parseFloat(bodyValues[f.name])
              : bodyValues[f.name];
          }
        });
        data = await api(apiPath, { method: endpoint.method, body: JSON.stringify(bodyPayload) });
      } else {
        data = await api(apiPath);
      }
      const elapsed = Math.round(performance.now() - start);
      setResult({
        status: data ? 200 : 'Error',
        time: elapsed,
        body: data ? JSON.stringify(data, null, 2) : 'Request failed. Check console for details.',
      });
    } catch (err) {
      const elapsed = Math.round(performance.now() - start);
      setResult({ status: 'Error', time: elapsed, body: err.message });
    }
    setLoading(false);
  };

  const allParams = [
    ...(endpoint.params || []),
  ];
  const bodyFields = endpoint.body?.fields || [];
  const hasInputs = allParams.length > 0 || bodyFields.length > 0;

  return (
    <div className={s.tryItPanel}>
      <div className={s.tryItTitle}>Try It</div>

      {hasInputs && (
        <div className={s.tryItInputs}>
          {allParams.map(p => (
            <div key={p.name} className={s.tryItField}>
              <label className={s.tryItLabel}>
                {p.name} {p.required && <span className={s.tryItRequired}>*</span>}
              </label>
              <input
                type={p.type === 'integer' || p.type === 'number' ? 'number' : 'text'}
                placeholder={p.description}
                value={paramValues[p.name] || ''}
                onChange={e => updateParam(p.name, e.target.value)}
                className={s.tryItInput}
              />
            </div>
          ))}
          {bodyFields.map(f => (
            <div key={f.name} className={s.tryItField}>
              <label className={s.tryItLabel}>
                {f.name} {f.required && <span className={s.tryItRequired}>*</span>}
                <span className={s.tryItLabelType}>(body)</span>
              </label>
              <input
                type={f.type === 'integer' || f.type === 'number' ? 'number' : 'text'}
                placeholder={f.description}
                value={bodyValues[f.name] || ''}
                onChange={e => updateBody(f.name, e.target.value)}
                className={s.tryItInput}
              />
            </div>
          ))}
        </div>
      )}

      <button onClick={handleSend} disabled={loading} className={s.tryItSendBtn}>
        {loading ? 'Sending...' : 'Send Request'}
      </button>

      <AnimatePresence>
        {result && (
          <motion.div
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: 'auto' }}
            exit={{ opacity: 0, height: 0 }}
            className={s.tryItResultWrap}
          >
            <div className={s.tryItResultHeader}>
              <span
                className={s.tryItStatusBadge}
                style={{
                  color: result.status === 200 ? '#22C55E' : '#EF4444',
                  borderColor: result.status === 200 ? 'rgba(34,197,94,0.3)' : 'rgba(239,68,68,0.3)',
                  background: result.status === 200 ? 'rgba(34,197,94,0.1)' : 'rgba(239,68,68,0.1)',
                }}
              >
                {result.status}
              </span>
              <span className={s.tryItTime}>{result.time}ms</span>
            </div>
            <pre className={s.tryItResponseBody}>{result.body}</pre>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

